using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Set up options with the default reflection-based resolver ---
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver(),
    WriteIndented    = true
};

// ================================================================
// 1. Strongly-typed metadata: GetTypeInfo<T>()
//    Returns JsonTypeInfo<T> directly — no cast needed.
// ================================================================
JsonTypeInfo<WeatherForecast> typedInfo = 
    (JsonTypeInfo<WeatherForecast>)options.GetTypeInfo(typeof(WeatherForecast));

Console.WriteLine($"Type  : {typedInfo.Type.Name}");
Console.WriteLine($"Kind  : {typedInfo.Kind}");
Console.WriteLine($"Props : {typedInfo.Properties.Count}");

var sample = new WeatherForecast("Seattle", 62);
string json = JsonSerializer.Serialize(sample, typedInfo);
Console.WriteLine($"JSON  : {json}");
Console.WriteLine();

// ================================================================
// 2. Probe without throwing: TryGetTypeInfo()
//    Returns false instead of throwing when metadata isn't available.
// ================================================================

// 2a. A type the resolver *can* handle
if (options.TryGetTypeInfo(typeof(WeatherForecast), out JsonTypeInfo? info))
{
    Console.WriteLine($"[Probe] WeatherForecast → available (Kind={info!.Kind})");
}

// 2b. Use a source-gen-only resolver that knows about only one type,
//     so asking for anything else returns false instead of throwing.
var limitedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = SmallContext.Default
};

bool found = limitedOptions.TryGetTypeInfo(typeof(WeatherForecast), out _);
Console.WriteLine($"[Probe] WeatherForecast via SmallContext → {found}");

found = limitedOptions.TryGetTypeInfo(typeof(string), out _);
Console.WriteLine($"[Probe] String via SmallContext          → {found}");

// --- Types -----------------------------------------------------------
record WeatherForecast(string City, int TempF);

// Source-gen context that only knows about `int`
[JsonSerializable(typeof(int))]
partial class SmallContext : JsonSerializerContext;

